import { readFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';
import { generateText } from 'ai';
import { model } from './model.js';
import { fetchABITool, fetchSourceCodeTool } from '../tools/research.js';
import { fetchABI } from '../tools/explorer.js';
import { detectERCPatterns } from '../tools/erc.js';

const __dirname = dirname(fileURLToPath(import.meta.url));
const SYSTEM_PROMPT = readFileSync(join(__dirname, 'prompts/research-system.md'), 'utf8');

/**
 * Run the research stage for a smart contract.
 * @param {string} contractAddress
 * @returns {Promise<object>} structured research summary
 */
export async function runResearch(contractAddress) {
  const { text } = await generateText({
    model,
    system: SYSTEM_PROMPT,
    prompt: `Research the smart contract at address ${contractAddress} on Base Mainnet (chainId 8453). Use the tools to fetch the ABI and source code. Then return a JSON object with your findings.`,
    tools: { fetchABI: fetchABITool, fetchSourceCode: fetchSourceCodeTool },
    maxSteps: 10,
  });

  // Extract JSON from the response text
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    throw new Error(`Research stage did not return valid JSON. Response: ${text.slice(0, 200)}`);
  }

  const summary = JSON.parse(jsonMatch[0]);

  // Detect ERC patterns directly from the ABI (deterministic, no LLM needed)
  const abi = await fetchABI(contractAddress);
  const ercPatterns = abi ? detectERCPatterns(abi) : [];

  return {
    contractAddress,
    chainId: 8453,
    ercPatterns,
    ...summary,
  };
}

