 1→import { readFileSync } from 'fs';
 2→import { dirname, join } from 'path';
 3→import { fileURLToPath } from 'url';
 4→import { generateText } from 'ai';
 5→import { model } from './model.js';
 6→import { fetchABITool, fetchSourceCodeTool } from '../tools/research.js';
 7→import { fetchABI } from '../tools/explorer.js';
 8→import { detectERCPatterns } from '../tools/erc.js';
 9→
10→const __dirname = dirname(fileURLToPath(import.meta.url));
11→const SYSTEM_PROMPT = readFileSync(join(__dirname, 'prompts/research-system.md'), 'utf8');
12→
13→/**
14→ * Run the research stage for a smart contract.
15→ * @param {string} contractAddress
16→ * @returns {Promise<object>} structured research summary
17→ */
18→export async function runResearch(contractAddress) {
19→  const { text } = await generateText({
20→    model,
21→    system: SYSTEM_PROMPT,
22→    prompt: `Research the smart contract at address ${contractAddress} on Base Mainnet (chainId 8453). Use the tools to fetch the ABI and source code. Then return a JSON object with your findings.`,
23→    tools: { fetchABI: fetchABITool, fetchSourceCode: fetchSourceCodeTool },
24→    maxSteps: 10,
25→  });
26→
27→  // Extract JSON from the response text
28→  const jsonMatch = text.match(/\{[\s\S]*\}/);
29→  if (!jsonMatch) {
30→    throw new Error(`Research stage did not return valid JSON. Response: ${text.slice(0, 200)}`);
31→  }
32→
33→  const summary = JSON.parse(jsonMatch[0]);
34→
35→  // Detect ERC patterns directly from the ABI (deterministic, no LLM needed)
36→  const abi = await fetchABI(contractAddress);
37→  const ercPatterns = abi ? detectERCPatterns(abi) : [];
38→
39→  return {
40→    contractAddress,
41→    chainId: 8453,
42→    ercPatterns,
43→    ...summary,
44→  };
45→}
